"use client";
import * as React from "react";
import { checkboxAnatomy } from "@tessera/core";
import { useControllableState } from "../utils/hooks";
import { CheckIcon } from "../utils/icons";

export interface CheckboxProps {
  label: React.ReactNode;
  checked?: boolean;
  defaultChecked?: boolean;
  onCheckedChange?: (checked: boolean) => void;
  disabled?: boolean;
  name?: string;
  value?: string;
  required?: boolean;
}

/** Built on a real (visually hidden) input: native forms and a11y for free. */
export const Checkbox = React.forwardRef<HTMLInputElement, CheckboxProps>(function Checkbox(
  { label, checked, defaultChecked = false, onCheckedChange, disabled, name, value, required },
  ref
) {
  const [isChecked, setChecked] = useControllableState({
    value: checked,
    defaultValue: defaultChecked,
    onChange: onCheckedChange,
  });
  const state = isChecked ? "checked" : "unchecked";

  return (
    <label {...checkboxAnatomy.attrs("root")} data-disabled={disabled || undefined}>
      <input
        type="checkbox"
        data-visually-hidden=""
        ref={ref}
        checked={isChecked}
        onChange={(event) => setChecked(event.target.checked)}
        disabled={disabled}
        name={name}
        value={value}
        required={required}
      />
      <span {...checkboxAnatomy.attrs("control")} data-state={state} aria-hidden>
        {isChecked && (
          <span {...checkboxAnatomy.attrs("indicator")}>
            <CheckIcon />
          </span>
        )}
      </span>
      <span {...checkboxAnatomy.attrs("label")}>{label}</span>
    </label>
  );
});

@layer tessera.recipes {
  [data-scope="checkbox"][data-part="root"] {
    display: inline-flex;
    align-items: center;
    gap: var(--ts-space-2);
    cursor: pointer;
  }

  [data-scope="checkbox"][data-part="root"][data-disabled] {
    cursor: not-allowed;
  }

  [data-scope="checkbox"][data-part="control"] {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 1.125rem;
    height: 1.125rem;
    border: 1px solid var(--ts-border-strong);
    border-radius: var(--ts-radius-sm);
    background: var(--ts-bg-surface);
    color: var(--ts-fg-onAccent);
    flex-shrink: 0;
    transition:
      background-color var(--ts-duration-fast) var(--ts-easing-standard),
      border-color var(--ts-duration-fast) var(--ts-easing-standard);
  }

  [data-scope="checkbox"][data-part="control"][data-state="checked"] {
    background: var(--ts-accent-default);
    border-color: var(--ts-accent-default);
  }

  [data-scope="checkbox"][data-part="indicator"] {
    display: inline-flex;
    width: 0.75rem;
    height: 0.75rem;
  }

  [data-scope="checkbox"][data-part="label"] {
    font-size: var(--ts-font-size-sm);
    color: var(--ts-fg-default);
    user-select: none;
  }
}
